public async Task PurchaseTicketsAsync(int eventId, int quantity)
{
    using var context = new ApplicationDbContext();
    var @event = await context.Events
        .FirstOrDefaultAsync(e => e.Id == eventId);

    if (@event == null || @event.RemainingSeats < quantity)
        throw new ArgumentException("Invalid event or insufficient remaining seats.");

    var updatedEvent = await context.Entry(@event).Reference(e => e.Events).LoadAsync();

    var originalRowVersion = @event.RowVersion;
    var newTickets = quantity;

    try
    {
        // Attempt to update the event in one transaction, supporting optimistic concurrency
        await context.Database.BeginTransactionAsync();

        @event.RemainingSeats -= newTickets;
        @event.RowVersion = BitConverter.GetBytes(BitConverter.ToInt64(@event.RowVersion, 0) + 1);

        updatedEvent.CurrentValues.SetValues(@event);

        await context.SaveChangesAsync();

        await context.Database.CommitTransactionAsync();
    }
    catch (DbUpdateConcurrencyException ex)
    {
        // Concurrency conflict, try again with fresh data
        @event = await context.Events
            .FirstOrDefaultAsync(e => e.Id == eventId && e.RowVersion == originalRowVersion);

        if (@event != null)
        {
            throw new OptimisticConcurrencyException();
        }
    }
